// StakerClaimedRewards includes the detailed states for claimed rewards.
//
// The current total rewards assets of a staker in an AVS are calculated as:
// (outstanding_rewards + delegation_rewards + pending_undelegation_rewards +
// withdrawable_rewards - pending_slashed_rewards).
// This value reflects the staker’s current reward assets after considering slashing,
// and thus represents the current asset balance rather than the historical total earned.
//
// The total slashed rewards for a staker can be calculated as:
// (historical_total_rewards - outstanding_rewards - withdrawn_rewards - delegation_rewards
// - withdrawable_rewards - pending_undelegation_rewards + pending_slashed_rewards).
// The historical_total_rewards includes both withdrawn rewards and slashed rewards, in addition
// to the current balance.
type StakerClaimedRewards struct {
	// outstanding_rewards represents the rewards that have been claimed by the staker
	// but not yet withdrawn; they can either be withdrawn or automatically redelegated.
	OutstandingRewards github_com_cosmos_cosmos_sdk_types.DecCoins `protobuf:"bytes,1,rep,name=outstanding_rewards,json=outstandingRewards,proto3,castrepeated=github.com/cosmos/cosmos-sdk/types.DecCoins" json:"outstanding_rewards"`
	// withdrawn_rewards represents the withdrawn rewards for the staker
	WithdrawnRewards github_com_cosmos_cosmos_sdk_types.DecCoins `protobuf:"bytes,2,rep,name=withdrawn_rewards,json=withdrawnRewards,proto3,castrepeated=github.com/cosmos/cosmos-sdk/types.DecCoins" json:"withdrawn_rewards"`
	// historical_total_rewards represents the historical total rewards that are claimed by this staker,
	HistoricalTotalRewards github_com_cosmos_cosmos_sdk_types.DecCoins `protobuf:"bytes,3,rep,name=historical_total_rewards,json=historicalTotalRewards,proto3,castrepeated=github.com/cosmos/cosmos-sdk/types.DecCoins" json:"historical_total_rewards"`
	// delegation_rewards_shares represents the shares of rewards that are lazily claimed
	// and currently redelegated for compounding. The shares might come from different operators,
	// as the staker may change the default redelegation operator.
	DelegationRewardsShares []RewardsDelegationShare `protobuf:"bytes,4,rep,name=delegation_rewards_shares,json=delegationRewardsShares,proto3" json:"delegation_rewards_shares"`
	// pending_undelegation_rewards represents the pending undelegation rewards
	// through a reward undelegation transaction.
	PendingUndelegationRewards github_com_cosmos_cosmos_sdk_types.DecCoins `protobuf:"bytes,5,rep,name=pending_undelegation_rewards,json=pendingUndelegationRewards,proto3,castrepeated=github.com/cosmos/cosmos-sdk/types.DecCoins" json:"pending_undelegation_rewards"`
	// pending_slashed_rewards represents rewards from pending undelegations
	// that have been slashed. The slashing may result from malicious behavior
	// or from instant unbonding. This field ensures accurate calculation
	// of the current staker’s rewards in an AVS by excluding the effect of slashed
	// pending undelegations.
	PendingSlashedRewards github_com_cosmos_cosmos_sdk_types.DecCoins `protobuf:"bytes,6,rep,name=pending_slashed_rewards,json=pendingSlashedRewards,proto3,castrepeated=github.com/cosmos/cosmos-sdk/types.DecCoins" json:"pending_slashed_rewards"`
	// withdrawable_rewards are rewards that can be withdrawn from completed undelegations.
	WithdrawableRewards github_com_cosmos_cosmos_sdk_types.DecCoins `protobuf:"bytes,7,rep,name=withdrawable_rewards,json=withdrawableRewards,proto3,castrepeated=github.com/cosmos/cosmos-sdk/types.DecCoins" json:"withdrawable_rewards"`
}

